import{_ as t,o as s,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"Suivi des jobs","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/jobs.md","filePath":"fr/guide/jobs.md"}'),o={name:"fr/guide/jobs.md"};function n(i,e,l,d,u,c){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="suivi-des-jobs" tabindex="-1">Suivi des jobs <a class="header-anchor" href="#suivi-des-jobs" aria-label="Permalink to &quot;Suivi des jobs&quot;">​</a></h1><p>Toutes les opérations longues dans Nid (suppression en masse, archivage, scan de newsletters, etc.) sont exécutées en arrière-plan via des <strong>jobs</strong>. La page Jobs vous permet de suivre leur progression.</p><hr><h2 id="liste-des-jobs" tabindex="-1">Liste des jobs <a class="header-anchor" href="#liste-des-jobs" aria-label="Permalink to &quot;Liste des jobs&quot;">​</a></h2><p>La page <strong>Jobs</strong> affiche tous vos jobs avec leur statut actuel :</p><table tabindex="0"><thead><tr><th>Statut</th><th>Signification</th></tr></thead><tbody><tr><td>🟡 <strong>En attente</strong></td><td>Le job est dans la queue, pas encore démarré</td></tr><tr><td>🔵 <strong>En cours</strong></td><td>Le job est en cours d&#39;exécution</td></tr><tr><td>🟢 <strong>Terminé</strong></td><td>Le job s&#39;est terminé avec succès</td></tr><tr><td>🔴 <strong>En erreur</strong></td><td>Le job a échoué (3 tentatives automatiques épuisées)</td></tr><tr><td>⚪ <strong>Annulé</strong></td><td>Le job a été annulé manuellement</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Jobs avec plusieurs jobs dans différents statuts</em></p></blockquote><hr><h2 id="types-de-jobs" tabindex="-1">Types de jobs <a class="header-anchor" href="#types-de-jobs" aria-label="Permalink to &quot;Types de jobs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Déclenché par</th></tr></thead><tbody><tr><td><strong>Opération groupée</strong></td><td>Actions en masse dans Mes mails (supprimer, labelliser, etc.)</td></tr><tr><td><strong>Archivage</strong></td><td>Archivage sur NAS depuis Mes mails</td></tr><tr><td><strong>Exécution de règle</strong></td><td>Lancement manuel ou planifié d&#39;une règle</td></tr><tr><td><strong>Scan newsletters</strong></td><td>Scan de la page Newsletters</td></tr><tr><td><strong>Scan pixels espions</strong></td><td>Scan depuis la page Vie privée</td></tr><tr><td><strong>Scan PII</strong></td><td>Scan de données sensibles depuis Vie privée</td></tr><tr><td><strong>Chiffrement archives</strong></td><td>Chiffrement depuis Vie privée</td></tr></tbody></table><hr><h2 id="suivi-en-temps-reel" tabindex="-1">Suivi en temps réel <a class="header-anchor" href="#suivi-en-temps-reel" aria-label="Permalink to &quot;Suivi en temps réel&quot;">​</a></h2><p>Quand un job est lancé, une <strong>modale de progression</strong> s&#39;affiche automatiquement :</p><ul><li>Barre de progression (ex. : 42/150 mails traités)</li><li>Pourcentage de completion</li><li>Statut en temps réel</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : modale de progression d&#39;un job avec barre de progression</em></p></blockquote><p>La mise à jour est instantanée grâce aux <strong>Server-Sent Events</strong> (SSE) — pas besoin de rafraîchir la page.</p><p>Vous pouvez fermer la modale sans interrompre le job. Il continue en arrière-plan.</p><hr><h2 id="annuler-un-job" tabindex="-1">Annuler un job <a class="header-anchor" href="#annuler-un-job" aria-label="Permalink to &quot;Annuler un job&quot;">​</a></h2><p>Pour annuler un job en attente ou en cours :</p><ol><li>Cliquez sur le bouton <strong>Annuler</strong> à côté du job</li><li>Le job passe au statut <strong>Annulé</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Annulation partielle</p><p>Les mails déjà traités avant l&#39;annulation ne sont pas restaurés. Par exemple, si 50 mails sur 100 ont été supprimés quand vous annulez, les 50 premiers restent supprimés.</p></div><hr><h2 id="detail-d-un-job" tabindex="-1">Détail d&#39;un job <a class="header-anchor" href="#detail-d-un-job" aria-label="Permalink to &quot;Détail d&#39;un job&quot;">​</a></h2><p>Cliquez sur un job pour voir ses détails :</p><ul><li>Type d&#39;opération</li><li>Compte Gmail concerné</li><li>Nombre de mails traités / total</li><li>Date de création et de fin</li><li>Message d&#39;erreur (en cas d&#39;échec)</li></ul><hr><h2 id="retry-automatique" tabindex="-1">Retry automatique <a class="header-anchor" href="#retry-automatique" aria-label="Permalink to &quot;Retry automatique&quot;">​</a></h2><p>En cas d&#39;erreur (ex. : timeout Gmail API), les jobs sont automatiquement relancés jusqu&#39;à <strong>3 fois</strong> avec un délai exponentiel :</p><ul><li>1ère tentative : immédiate</li><li>2ème tentative : après 2 secondes</li><li>3ème tentative : après 4 secondes</li><li>Après 3 échecs : le job passe en statut <strong>En erreur</strong></li></ul><hr><h2 id="notifications-de-fin-de-job" tabindex="-1">Notifications de fin de job <a class="header-anchor" href="#notifications-de-fin-de-job" aria-label="Permalink to &quot;Notifications de fin de job&quot;">​</a></h2><p>Quand un job se termine (succès ou échec), vous recevez une notification :</p><ul><li><strong>In-app</strong> : dans la cloche de notifications (🔔)</li><li><strong>Toast</strong> : pop-up temporaire en bas de page (si activé dans les <a href="./notifications.html">préférences</a>)</li><li><strong>Webhook</strong> : push vers Discord, Slack, etc. (si <a href="./notifications.html#webhooks">configuré</a>)</li></ul>',34)])])}const h=t(o,[["render",n]]);export{b as __pageData,h as default};
